   209→  LLVM_ABI bool isScalableTy(SmallPtrSetImpl<const Type *> &Visited) const;
   210→  LLVM_ABI bool isScalableTy() const;
   211→
   212→  /// Return true if this type is or contains a target extension type that
   213→  /// disallows being used as a global.
   214→  LLVM_ABI bool
   215→  containsNonGlobalTargetExtType(SmallPtrSetImpl<const Type *> &Visited) const;
   216→  LLVM_ABI bool containsNonGlobalTargetExtType() const;
   217→
   218→  /// Return true if this type is or contains a target extension type that
   219→  /// disallows being used as a local.
   220→  LLVM_ABI bool
   221→  containsNonLocalTargetExtType(SmallPtrSetImpl<const Type *> &Visited) const;
